import{_ as o,c as a,o as r,a1 as s}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Log de Atualizações: Histórico de Versões | opencode-md-table-formatter","description":"Entenda a evolução de versões e novos recursos do opencode-md-table-formatter. Veja os recursos do v0.1.0, incluindo formatação automática e cache de largura.","frontmatter":{"title":"Log de Atualizações: Histórico de Versões | opencode-md-table-formatter","sidebarTitle":"Visão geral das mudanças de versão","subtitle":"Log de Atualizações: Histórico de Versões e Registro de Alterações","description":"Entenda a evolução de versões e novos recursos do opencode-md-table-formatter. Veja os recursos do v0.1.0, incluindo formatação automática e cache de largura.","tags":["log de atualizações","histórico de versões","notas de versão"],"prerequisite":[],"order":90},"headers":[],"relativePath":"pt/franlol/opencode-md-table-formatter/changelog/release-notes/index.md","filePath":"pt/franlol/opencode-md-table-formatter/changelog/release-notes/index.md"}'),t={name:"pt/franlol/opencode-md-table-formatter/changelog/release-notes/index.md"};function i(l,e,n,d,c,m){return r(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="log-de-atualizacoes-historico-de-versoes-e-registro-de-alteracoes" tabindex="-1">Log de Atualizações: Histórico de Versões e Registro de Alterações <a class="header-anchor" href="#log-de-atualizacoes-historico-de-versoes-e-registro-de-alteracoes" aria-label="Permalink to &quot;Log de Atualizações: Histórico de Versões e Registro de Alterações&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">O que você será capaz de fazer após esta aula</p><ul><li>Acompanhar a evolução de versões do plugin</li><li>Entender os novos recursos e correções de cada versão</li><li>Dominar limitações conhecidas e detalhes técnicos</li><li>Entender possíveis melhorias futuras</li></ul></div><hr><h2 id="_0-1-0-2025-01-07" tabindex="-1">[0.1.0] - 2025-01-07 <a class="header-anchor" href="#_0-1-0-2025-01-07" aria-label="Permalink to &quot;[0.1.0] - 2025-01-07&quot;">​</a></h2><h3 id="novos-recursos" tabindex="-1">Novos recursos <a class="header-anchor" href="#novos-recursos" aria-label="Permalink to &quot;Novos recursos&quot;">​</a></h3><p>Esta é a <strong>versão de lançamento inicial</strong> do opencode-md-table-formatter, contendo os seguintes recursos principais:</p><ul><li><strong>Formatação automática de tabelas</strong>: Formata automaticamente tabelas Markdown geradas por IA através do hook <code>experimental.text.complete</code></li><li><strong>Suporte ao modo de ocultação</strong>: Processa corretamente símbolos Markdown ocultos (como <code>**</code>, <code>*</code>) ao calcular a largura</li><li><strong>Processamento de Markdown aninhado</strong>: Suporta sintaxe Markdown aninhada em profundidade arbitrária, usando algoritmo de remoção de múltiplas passagens</li><li><strong>Proteção de blocos de código</strong>: Símbolos Markdown dentro do código em linha (<code>`code`</code>) permanecem na forma literal, não participando do cálculo de largura</li><li><strong>Suporte a métodos de alinhamento</strong>: Suporta alinhamento à esquerda (<code>---</code> ou <code>:---</code>), alinhamento centralizado (<code>:---:</code>), alinhamento à direita (<code>---:</code>)</li><li><strong>Otimização de cache de largura</strong>: Cache os resultados de cálculo de largura de exibição de strings, melhorando o desempenho</li><li><strong>Validação de tabelas inválidas</strong>: Valida automaticamente a estrutura da tabela, tabelas inválidas recebem comentário de erro</li><li><strong>Suporte a múltiplos caracteres</strong>: Suporta Emoji, caracteres Unicode, células vazias, conteúdo muito longo</li><li><strong>Tratamento silencioso de erros</strong>: Falhas na formatação não interrompem o fluxo de trabalho do OpenCode</li></ul><h3 id="detalhes-tecnicos" tabindex="-1">Detalhes técnicos <a class="header-anchor" href="#detalhes-tecnicos" aria-label="Permalink to &quot;Detalhes técnicos&quot;">​</a></h3><p>Esta versão contém aproximadamente <strong>230 linhas de código TypeScript pronto para produção</strong>:</p><ul><li><strong>12 funções</strong>: Responsabilidades claras, bem separadas</li><li><strong>Segurança de tipos</strong>: Uso correto da interface <code>Hooks</code></li><li><strong>Limpeza inteligente de cache</strong>: Aciona limpeza quando o número de operações excede 100 ou o número de entradas de cache excede 1000</li><li><strong>Processamento de múltiplas passagens com regex</strong>: Suporta remoção de símbolos Markdown com profundidade de aninhamento arbitrária</li></ul><div class="tip custom-block"><p class="custom-block-title">Mecanismo de cache</p><p>O cache foi projetado para otimizar o cálculo de largura de conteúdo repetido. Por exemplo, quando o mesmo texto de célula aparece várias vezes em uma tabela, a largura é calculada apenas uma vez, e as leituras subsequentes são feitas diretamente do cache.</p></div><h3 id="limitacoes-conhecidas" tabindex="-1">Limitações conhecidas <a class="header-anchor" href="#limitacoes-conhecidas" aria-label="Permalink to &quot;Limitações conhecidas&quot;">​</a></h3><p>Esta versão não suporta os seguintes cenários:</p><ul><li><strong>Tabelas HTML</strong>: Suporta apenas tabelas de pipe Markdown (Pipe Table)</li><li><strong>Células multilinha</strong>: Não suporta células contendo tags <code>&lt;br&gt;</code></li><li><strong>Tabelas sem linha separadora</strong>: As tabelas devem conter uma linha separadora (<code>|---|</code>) para serem formatadas</li><li><strong>Requisitos de dependência</strong>: Requer <code>@opencode-ai/plugin</code> &gt;= 0.13.7 (usa o hook <code>experimental.text.complete</code> não documentado)</li></ul><div class="info custom-block"><p class="custom-block-title">Requisitos de versão</p><p>O plugin requer OpenCode &gt;= 1.0.137 e <code>@opencode-ai/plugin</code> &gt;= 0.13.7 para funcionar corretamente.</p></div><hr><h2 id="planos-futuros" tabindex="-1">Planos futuros <a class="header-anchor" href="#planos-futuros" aria-label="Permalink to &quot;Planos futuros&quot;">​</a></h2><p>Os seguintes recursos estão planejados para serem implementados em versões futuras:</p><ul><li><strong>Opções de configuração</strong>: Suportar personalização de largura mínima/máxima de colunas, desabilitar recursos específicos</li><li><strong>Suporte a tabelas sem cabeçalho</strong>: Formatar tabelas sem linhas de cabeçalho</li><li><strong>Otimização de desempenho</strong>: Análise e otimização de desempenho para tabelas muito grandes (100+ linhas)</li><li><strong>Mais opções de alinhamento</strong>: Expandir a sintaxe e funcionalidade dos métodos de alinhamento</li></ul><div class="tip custom-block"><p class="custom-block-title">Participar da contribuição</p><p>Se você tem sugestões de recursos ou deseja contribuir com código, sinta-se à vontade para apresentar suas ideias em <a href="https://github.com/franlol/opencode-md-table-formatter/issues" target="_blank" rel="noreferrer">GitHub Issues</a>.</p></div><hr><h2 id="formato-de-registro-de-alteracoes" tabindex="-1">Formato de registro de alterações <a class="header-anchor" href="#formato-de-registro-de-alteracoes" aria-label="Permalink to &quot;Formato de registro de alterações&quot;">​</a></h2><p>O log de atualizações deste projeto segue o formato <a href="https://keepachangelog.com/en/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, e os números de versão seguem a <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Especificação de Versionamento Semântico (Semantic Versioning)</a>.</p><p><strong>Formato do número da versão</strong>: <code>MAJOR.MINOR.PATCH</code></p><ul><li><strong>MAJOR</strong>: Alterações de API incompatíveis</li><li><strong>MINOR</strong>: Novos recursos compatíveis com versões anteriores</li><li><strong>PATCH</strong>: Correções de problemas compatíveis com versões anteriores</li></ul><p><strong>Tipos de alterações</strong>:</p><ul><li><strong>Added</strong>: Novos recursos</li><li><strong>Changed</strong>: Alterações em recursos existentes</li><li><strong>Deprecated</strong>: Recursos que serão removidos em breve</li><li><strong>Removed</strong>: Recursos removidos</li><li><strong>Fixed</strong>: Correções de problemas</li><li><strong>Security</strong>: Correções relacionadas à segurança</li></ul><hr><h2 id="ordem-de-leitura-recomendada" tabindex="-1">Ordem de leitura recomendada <a class="header-anchor" href="#ordem-de-leitura-recomendada" aria-label="Permalink to &quot;Ordem de leitura recomendada&quot;">​</a></h2><p>Se você é um novo usuário, recomenda-se aprender na seguinte ordem:</p><ol><li><a href="./../../start/getting-started/">Comece em 1 minuto: Instalação e Configuração</a> —— Comece rapidamente</li><li><a href="./../../start/features/">Visão Geral de Recursos: A Mágica da Formatação Automática</a> —— Entenda os recursos principais</li><li><a href="./../../faq/troubleshooting/">Perguntas Frequentes: O que fazer quando a tabela não é formatada</a> —— Solução de problemas</li><li><a href="./../../appendix/limitations/">Limitações Conhecidas: Onde estão os limites do plugin</a> —— Entenda as limitações</li></ol>',31)])])}const g=o(t,[["render",i]]);export{p as __pageData,g as default};
